import{_ as i,c as l,o,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.32: Aura Theme Debuts, Major Language Support Upgrade","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.32.md","filePath":"en/changelog/v1.1.32.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.32.md"};function n(s,t,d,h,p,c){return o(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="v1-1-32-aura-theme-debuts-major-language-support-upgrade" tabindex="-1">v1.1.32: Aura Theme Debuts, Major Language Support Upgrade <a class="header-anchor" href="#v1-1-32-aura-theme-debuts-major-language-support-upgrade" aria-label="Permalink to “v1.1.32: Aura Theme Debuts, Major Language Support Upgrade”">​</a></h1><p><strong>Release Date</strong>: January 22, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update brings the brand new Aura theme, supports Arabic, Norwegian, and Brazilian Portuguese, adds image rendering, session deletion, and other practical features, with significantly improved connection reliability.</p><hr><h2 id="new-look-aura-theme" tabindex="-1">New Look: Aura Theme <a class="header-anchor" href="#new-look-aura-theme" aria-label="Permalink to “New Look: Aura Theme”">​</a></h2><h3 id="what-is-aura" tabindex="-1">What is Aura? <a class="header-anchor" href="#what-is-aura" aria-label="Permalink to “What is Aura?”">​</a></h3><p>Aura is a brand new theme style that provides a unique visual experience for OpenCode. If you like different code color schemes, you now have a new choice!</p><h3 id="how-to-switch" tabindex="-1">How to switch? <a class="header-anchor" href="#how-to-switch" aria-label="Permalink to “How to switch?”">​</a></h3><ol><li>Open <strong>Settings</strong></li><li>Find <strong>Theme</strong></li><li>Select <strong>Aura</strong></li></ol><hr><h2 id="major-language-support-upgrade" tabindex="-1">Major Language Support Upgrade <a class="header-anchor" href="#major-language-support-upgrade" aria-label="Permalink to “Major Language Support Upgrade”">​</a></h2><h3 id="new-languages" tabindex="-1">New Languages <a class="header-anchor" href="#new-languages" aria-label="Permalink to “New Languages”">​</a></h3><p>Now supports more languages - OpenCode is becoming increasingly international!</p><ul><li>🇧🇷 <strong>Brazilian Portuguese</strong> (@ygorsimoes)</li><li>🇳🇴 <strong>Norwegian</strong> (@Finityno)</li><li>🇸🇦 <strong>Arabic</strong> (@NourEldin-Osama)</li></ul><h3 id="how-to-switch-language" tabindex="-1">How to switch language? <a class="header-anchor" href="#how-to-switch-language" aria-label="Permalink to “How to switch language?”">​</a></h3><ol><li>Open <strong>Settings</strong></li><li>Find <strong>Language</strong></li><li>Select your preferred language</li></ol><hr><h2 id="new-feature-image-rendering" tabindex="-1">New Feature: Image Rendering <a class="header-anchor" href="#new-feature-image-rendering" aria-label="Permalink to “New Feature: Image Rendering”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Now you can see AI-generated images in sessions! Markdown rendering has been migrated to Rust for stronger performance.</p><h3 id="how-to-view" tabindex="-1">How to view? <a class="header-anchor" href="#how-to-view" aria-label="Permalink to “How to view?”">​</a></h3><p>When AI generates or returns images, they will display directly in the conversation without needing to navigate away.</p><hr><h2 id="new-feature-delete-sessions" tabindex="-1">New Feature: Delete Sessions <a class="header-anchor" href="#new-feature-delete-sessions" aria-label="Permalink to “New Feature: Delete Sessions”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>Now you can delete unwanted sessions! Keep your session list tidy.</p><h3 id="how-to-delete" tabindex="-1">How to delete? <a class="header-anchor" href="#how-to-delete" aria-label="Permalink to “How to delete?”">​</a></h3><p>In the Desktop app:</p><ol><li>Find the session you want to delete</li><li>Right-click or use the menu</li><li>Select <strong>Delete</strong></li></ol><hr><h2 id="new-feature-close-projects" tabindex="-1">New Feature: Close Projects <a class="header-anchor" href="#new-feature-close-projects" aria-label="Permalink to “New Feature: Close Projects”">​</a></h2><h3 id="what-was-updated-2" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-2" aria-label="Permalink to “What was updated?”">​</a></h3><p>You can now close projects directly from the hover card for easier management.</p><h3 id="how-to-close" tabindex="-1">How to close? <a class="header-anchor" href="#how-to-close" aria-label="Permalink to “How to close?”">​</a></h3><ol><li>Hover over the project</li><li>Find the close option in the hover card</li><li>Click close</li></ol><hr><h2 id="improvement-connection-reliability" tabindex="-1">Improvement: Connection Reliability <a class="header-anchor" href="#improvement-connection-reliability" aria-label="Permalink to “Improvement: Connection Reliability”">​</a></h2><h3 id="what-was-updated-3" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-3" aria-label="Permalink to “What was updated?”">​</a></h3><ul><li>Improved desktop app connection reliability</li><li>Fixed Windows path handling issues</li><li>Fixed NO_PROXY environment variable syntax errors</li></ul><h3 id="what-s-the-benefit" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>OpenCode Desktop will maintain connections more stably, especially during network fluctuations.</p><hr><h2 id="improvement-auto-scroll-and-message-display" tabindex="-1">Improvement: Auto-Scroll and Message Display <a class="header-anchor" href="#improvement-auto-scroll-and-message-display" aria-label="Permalink to “Improvement: Auto-Scroll and Message Display”">​</a></h2><h3 id="what-was-updated-4" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-4" aria-label="Permalink to “What was updated?”">​</a></h3><ul><li>Auto-scroll to bottom when new messages arrive</li><li>Auto-scroll to bottom after submitting prompt</li><li>Improved &quot;jump to latest&quot; button design and animation</li><li>Improved session hover state handling</li></ul><h3 id="what-s-the-benefit-1" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-1" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>Smoother conversation experience, won&#39;t miss AI&#39;s latest responses.</p><hr><h2 id="improvement-accessibility-enhancements" tabindex="-1">Improvement: Accessibility Enhancements <a class="header-anchor" href="#improvement-accessibility-enhancements" aria-label="Permalink to “Improvement: Accessibility Enhancements”">​</a></h2><h3 id="what-was-updated-5" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-5" aria-label="Permalink to “What was updated?”">​</a></h3><ul><li>Added accessibility translations</li><li>Improved session screen accessibility (@ndarilek)</li><li>Fixed focus being stolen by copy button</li></ul><h3 id="what-s-the-benefit-2" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-2" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>Better experience for users using assistive tools like screen readers.</p><hr><h2 id="improvement-font-stack-expansion" tabindex="-1">Improvement: Font Stack Expansion <a class="header-anchor" href="#improvement-font-stack-expansion" aria-label="Permalink to “Improvement: Font Stack Expansion”">​</a></h2><h3 id="what-was-updated-6" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-6" aria-label="Permalink to “What was updated?”">​</a></h3><p>Expanded font stacks, including macOS Nerd Font default names (@bewareoftheleopard).</p><h3 id="what-s-the-benefit-3" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-3" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>On macOS, the system&#39;s default Nerd Font will be used preferentially for more consistent display.</p><hr><h2 id="new-feature-remote-directory-mount" tabindex="-1">New Feature: Remote Directory Mount <a class="header-anchor" href="#new-feature-remote-directory-mount" aria-label="Permalink to “New Feature: Remote Directory Mount”">​</a></h2><h3 id="what-was-updated-7" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-7" aria-label="Permalink to “What was updated?”">​</a></h3><p>The TUI attach command now allows specifying remote directories (@gricha).</p><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3>',66),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode attach --dir /path/to/remote/directory")])],-1),a('<hr><h2 id="new-feature-terminal-panel-auto-open" tabindex="-1">New Feature: Terminal Panel Auto-Open <a class="header-anchor" href="#new-feature-terminal-panel-auto-open" aria-label="Permalink to “New Feature: Terminal Panel Auto-Open”">​</a></h2><h3 id="what-was-updated-8" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-8" aria-label="Permalink to “What was updated?”">​</a></h3><p>When creating a new terminal, the terminal panel opens automatically (@kearns-cu).</p><h3 id="what-s-the-benefit-4" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-4" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>No need to manually switch to terminal view, improving work efficiency.</p><hr><h2 id="new-feature-always-show-review-button" tabindex="-1">New Feature: Always Show Review Button <a class="header-anchor" href="#new-feature-always-show-review-button" aria-label="Permalink to “New Feature: Always Show Review Button”">​</a></h2><h3 id="what-was-updated-9" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-9" aria-label="Permalink to “What was updated?”">​</a></h3><p>The Toggle-Review button is now always visible (@DNGriffin).</p><h3 id="what-s-the-benefit-5" tabindex="-1">What&#39;s the benefit? <a class="header-anchor" href="#what-s-the-benefit-5" aria-label="Permalink to “What&#39;s the benefit?”">​</a></h3><p>Easier to switch code review mode.</p><hr><h2 id="technical-details-update" tabindex="-1">Technical Details Update <a class="header-anchor" href="#technical-details-update" aria-label="Permalink to “Technical Details Update”">​</a></h2><h3 id="acp-interface-change" tabindex="-1">ACP Interface Change <a class="header-anchor" href="#acp-interface-change" aria-label="Permalink to “ACP Interface Change”">​</a></h3><p><code>setSessionModel</code> has been renamed to <code>unstable_setSessionModel</code> (@maxious). If you&#39;re using this interface, you need to update accordingly.</p><h3 id="venice-prompt-caching" tabindex="-1">Venice Prompt Caching <a class="header-anchor" href="#venice-prompt-caching" aria-label="Permalink to “Venice Prompt Caching”">​</a></h3><p>Added prompt cache key support for Venice provider (@dpuyosa).</p><h3 id="litellm-proxy-compatibility" tabindex="-1">LiteLLM Proxy Compatibility <a class="header-anchor" href="#litellm-proxy-compatibility" aria-label="Permalink to “LiteLLM Proxy Compatibility”">​</a></h3><p>Included noop tool for LiteLLM proxy compatibility (@danielfrg).</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Want to try new theme</td><td>✅ <strong>Recommended upgrade</strong> (Aura theme)</td></tr><tr><td>Need multi-language support</td><td>✅ Recommended upgrade</td></tr><tr><td>Using Desktop version</td><td>✅ <strong>Highly recommended</strong> (major connectivity improvements)</td></tr><tr><td>Need image rendering feature</td><td>✅ Recommended upgrade</td></tr><tr><td>Need to delete sessions</td><td>✅ Recommended upgrade</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',24),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Revert handling of special characters in paths and git snapshot reading logic</li><li>Revert snapshot regression fix</li><li>Ensure cat command triggers external directory permission check in Bash tool</li><li>Print MCP stderr to OpenCode log file (@karta0807913)</li><li>Write refresh tokens to OpenAI auth in Codex (@CasualDeveloper)</li><li>Add workspace startup script to projects</li><li>Ensure images are properly returned as tool results</li><li>Rename <code>setSessionModel</code> to <code>unstable_setSessionModel</code> in ACP (@maxious)</li><li>Correct spelling of &#39;supercedes&#39; to &#39;supersedes&#39; (@luojiyin1987)</li><li>Add prompt cache key support for Venice provider (@dpuyosa)</li><li>Include noop tool in activeTools for LiteLLM proxy compatibility (@danielfrg)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Allow remote directory specification in attach command (@gricha)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Add Brazilian Portuguese locale support (@ygorsimoes)</li><li>Make &#39;Learn More&#39; link functional in theme settings (@LAG-4)</li><li>Render images in session review</li><li>Fix Windows path handling in app tests</li><li>Fix new session button in app</li><li>Add translations support to app</li><li>Delete sessions</li><li>Close projects from hover card</li><li>Don&#39;t auto-navigate to workspace after reset</li><li>Expand font stacks to include macOS Nerd Font default names (@bewareoftheleopard)</li><li>Clear session hover state on navigation (@kyashrathore)</li><li>Correct NO_PROXY environment variable syntax in desktop application (@Brendonovich)</li><li>Improve desktop connection reliability (@Brendonovich)</li><li>Add terminal smoke test to app test suite</li><li>Add file viewer smoke test</li><li>Add model picker smoke test</li><li>Add smoke test for @ attachment functionality</li><li>Add slash command smoke tests to app</li><li>Settings smoke tests</li><li>Fix type error in codebase</li><li>Fix TypeScript satisfies operator usage</li><li>Fix hover card scrolling behavior</li><li>Auto-scroll to bottom when new messages arrive</li><li>Add scrollbar styling to session page (@alexyaroshuk)</li><li>Add support for Norwegian translations (@Finityno)</li><li>Snap to bottom when user submits a prompt</li><li>Add accessibility translations to the app</li><li>Change project path tooltip position to bottom in desktop app (@ProdigyRahul)</li><li>Session screen accessibility improvements (@ndarilek)</li><li>Move markdown rendering to Rust in desktop app (@nexxeln)</li><li>Add 8px left margin to sidebar toggle on desktop</li><li>Match terminal toggle button size with sidebar and review toggles</li><li>Update jump to latest button with circular design and animation</li><li>Add Arabic language support (@NourEldin-Osama)</li><li>Always show Toggle-Review button in app (@DNGriffin)</li><li>Open terminal pane when creating new terminal (@kearns-cu)</li></ul><p><strong>Thank you to 24 community contributors:</strong></p><ul><li>@R44VC0RP: <ul><li>fix: scope PR recap to only PRs from today (#9905)</li></ul></li><li>@danielfrg: <ul><li>fix: include _noop tool in activeTools for LiteLLM proxy compatibility (#9912)</li></ul></li><li>@dpuyosa: <ul><li>feat: Add promptCacheKey for Venice provider (#9915)</li></ul></li><li>@kearns-cu: <ul><li>fix(app): open terminal pane when creating new terminal (#9926)</li></ul></li><li>@luojiyin1987: <ul><li>fix: correct spelling &#39;supercedes&#39; to &#39;supersedes&#39; (#9935)</li></ul></li><li>@maxious: <ul><li>fix(acp): rename setSessionModel to unstable_setSessionModel (#9940)</li></ul></li><li>@IdrisGit: <ul><li>docs: add API server section in CONTRIBUTING.md (#9888)</li></ul></li><li>@DNGriffin: <ul><li>feat(app): always show Toggle-Review button (#9944)</li></ul></li><li>@NourEldin-Osama: <ul><li>feat(i18n): add Arabic language support (#9947)</li></ul></li><li>@nexxeln: <ul><li>refactor(desktop): move markdown rendering to rust (#10000)</li></ul></li><li>@ndarilek: <ul><li>fix(app): session screen accessibility improvements (#9907)</li></ul></li><li>@ProdigyRahul: <ul><li>fix(desktop): change project path tooltip position to bottom (#9497)</li></ul></li><li>@Finityno: <ul><li>feat: Add support for Norwegian translations (#10018)</li></ul></li><li>@alexyaroshuk: <ul><li>feat(app): add scrollbar styling to session page (#10020)</li><li>fix(ui): prevent copy buttons from stealing focus from prompt input (#10084)</li></ul></li><li>@Brendonovich: <ul><li>fix(desktop): attempt to improve connection reliability</li><li>fix(desktop): correct NO_PROXY syntax</li></ul></li><li>@kyashrathore: <ul><li>fix(app): clear session hover state on navigation (#10031)</li></ul></li><li>@ryanmiville: <ul><li>fix(app): support ctrl-n/p in lists (#10036)</li></ul></li><li>@bewareoftheleopard: <ul><li>fix(desktop): Expand font stacks to include macOS Nerd Font default names (#10045)</li></ul></li><li>@CasualDeveloper: <ul><li>fix(codex): write refresh tokens to openai auth (#10010) (#10011)</li></ul></li><li>@karta0807913: <ul><li>feat(mcp log): print mcp stderr to opencode log file (#9982)</li></ul></li><li>@LAG-4: <ul><li>fix: make &#39;Learn More&#39; link functional in theme settings (#10078)</li></ul></li><li>@shubh73: <ul><li>feat(ui): add aura theme (#10056)</li></ul></li><li>@ygorsimoes: <ul><li>feat(i18n): add br locale support (#10086)</li></ul></li><li>@gricha: <ul><li>fix(attach): allow remote --dir (#8969)</li></ul></li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=i(r,[["render",n]]);export{m as __pageData,g as default};
